          {username: "冒慧敏", isAdminName: '否', mobile: '18547896584', dept: '立图开发组', createTime: '2024-04-28 14:30'},
        ],
        columnButton: [],
        columnWidth: "130",
        // tableColWidth:'155',
        isHiddenSelection: true, // 是否隐藏勾选
        isHiddenIndex: true, // 是否隐藏序号
        total: 150,
        pageSize: 20,
        currentPage: 1,
