export default {
  data() {
    return {
      tableConfig: {
        tableRefresh: true,
        tableLoading: false,
        tableHead: [
          {
            label: '用户名称',
            prop: 'username',
          },
          {
            label: '是否管理员',
            prop: 'isAdminName',
          },
          {
            label: '手机号',
            prop: 'mobile',
          },
          {
            label: '部门',
            prop: 'dept',
          },
          {
            label: '进度',
            prop: 'progress',
            isProgress: true
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [
          {username: "李辛",progress:'45', isAdminName: '是', mobile: '15974856942', dept: '立图开发组', createTime: '2024-04-28 14:30'},
          {username: "姜磊", isAdminName: '否', mobile: '18255060105', dept: '立图开发组', createTime: '2024-04-28 14:30'},
