        total: 150,
        pageSize: 20,
        currentPage: 1,
      },
    }
  },
  methods: {
    // 表格分页回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.$message.success({
        message: "这是‘分页跳转’操作",
        showClose: true,
        duration: 1000,
      });
    }
  }
}`,
